function ed_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function ed_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function ed_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function ed_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function ed_c($v){return strtoupper(trim((string)$v));}
function ed_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
